// contact.js
import React, { useRef } from 'react';


const Contact = () => {
  const form = useRef();

  const sendEmail = (e) => {
    e.preventDefault();

    emailjs.sendForm(
      'service_xxx123',     // Replace with your Service ID
      'template_yyy456',    // Replace with your Template ID
      form.current,
      'user_zzz789'         // Replace with your Public Key
    )
    .then((result) => {
      alert('Message Sent Successfully!');
      e.target.reset();
    }, (error) => {
      alert('Failed to send message, please try again.');
    });
  };

  return (
    <section id="contact" style={{ textAlign: "center", padding: "3rem 1rem" }}>
      <h2>Get In Touch</h2>
      <p>Let’s discuss opportunities and collaborate on exciting projects</p>
      
      <form ref={form} onSubmit={sendEmail} style={{ display: "flex", flexDirection: "column", gap: "1rem", maxWidth: "400px", margin: "auto" }}>
        <input
          type="text"
          name="from_name"
          placeholder="Your Name"
          required
          style={{ padding: "0.5rem", fontSize: "1rem" }}
        />
        <input
          type="email"
          name="from_email"
          placeholder="Your Email"
          required
          style={{ padding: "0.5rem", fontSize: "1rem" }}
        />
        <textarea
          name="message"
          placeholder="Your Message"
          rows="5"
          required
          style={{ padding: "0.5rem", fontSize: "1rem" }}
        ></textarea>
        <button
          type="submit"
          style={{ padding: "0.75rem", fontSize: "1rem", cursor: "pointer" }}
        >
          Send Message
        </button>
      </form>
    </section>
  );
};

export default Contact;
